140→function LoggedInShell({children}: {children: React.ReactNode}) {
141→  const {session} = useAuth();
142→  const userId = session?.user.id;
143→  const [toast, setToast] = useState<{message: string; visible: boolean}>({
144→    message: '',
145→    visible: false,
146→  });
147→
148→  const handleNewNotification = useCallback((payload: Record<string, unknown>) => {
149→    const message =
150→      (payload.message as string) || 'You have a new notification';
151→    setToast({message, visible: true});
152→  }, []);
153→
154→  const handleDismissToast = useCallback(() => {
155→    setToast(prev => ({...prev, visible: false}));
156→  }, []);
157→
158→  useRealtimeNotifications(userId, {
159→    onNewNotification: handleNewNotification,
160→  });
161→
162→  return (
163→    <View style={styles.shellContainer}>
164→      {children}
165→      <Toast
166→        message={toast.message}
167→        visible={toast.visible}
168→        onDismiss={handleDismissToast}
169→        type="info"
170→      />
171→    </View>
172→  );
173→}
